final:
module top_module(D, S, R, G, Q, QN);input  D ;
input  S ;
input  R ;
input  G ;
output Q ;
output QN ;
reg Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge G or posedge dbg_halt)
begin
    if (R == 1'b1)
        Q <= 1'b0;
    else if (S == 1'b1)
        Q <= 1'b1;
    else
        Q <= D;
end

assign QN = ~Q;

endmodule
